var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그러니까 제가 고통 받는 동안 처음 보는 아이들과 희희낙락하고 계셨단 말씀이로군요.","JPN":"つまり、私が苦しみを味わっている間、子どもたちと戯れていたというわけですね。","ENG":"So, while I was being tortured, you were entertaining some strange children.","TWN":"所以說，在我受苦的時候，您和初次見面的孩子們都很快樂的意思吧。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"매사를 부정적으로 바라보는 건 자네의 나쁜 습관이야.","JPN":"そうやって物事をネガティブに捉えるのは君の悪い癖だ。","ENG":"You look at things so negatively all the time.","TWN":"凡事都持否定態度是你的壞習慣。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아무것도 모르는 아이들을 도왔다고 표현해 주면 안 되겠나?","JPN":"何も知らない子どもたちを保護していた、そうだろう？","ENG":"Can't you say that I helped some innocent children instead?","TWN":"能不能好好幫助什麼都不懂的孩子們？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"후우......","JPN":"ふう……","ENG":"*Sigh...*","TWN":"呼啊......"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"제프티 바이오테크는 신약 개발과 의체 소재 생산으로 두각을 드러낸 바이오 기업입니다.","JPN":"ジェフティ・バイオテックは、新薬の開発と義体素材の生産に長けたバイオ企業です。","ENG":"Jehuty Biotech is a bioengineering company on the rise, specializing in new medicine development and mechanical prosthetic production.","TWN":"傑夫堤生物科技是透過開發新藥和生產假體材料而嶄露頭角的生物技術企業。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"최근 투자자들 사이에서 주목 받고 있는 유니콘 기업이죠. 인신매매 얘기는 처음 듣지만요.","JPN":"最近投資家の間でも注目されているユニコーン企業です。人身売買については初耳ですが。","ENG":"It's a unicorn that's gained popularity among business investors. I've never heard of its involvement in human trafficking before, though.","TWN":"這是最近備受投資者關注的獨角獸企業。 雖然第一次聽說販賣人口的事情。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 기업, 본사가 어디에 붙어 있나?","JPN":"その企業、本社はどこにある？","ENG":"Where is it headquartered?","TWN":"那個企業，總公司在哪裡？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"샤레이드 소재입니다. 그로니아 변경에 연구 시설이 있다더군요.","JPN":"所在地はシャレードです。グロニア辺境に研究施設を持っているそうですね。","ENG":"Charade. Its lab is located on the edge of Gronia.","TWN":"位於沙雷得，聽說在葛羅尼亞邊境有研究設施。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그로니아라...... 참 그 나라와는 좋은 일로 엮이는 법이 없군.","JPN":"グロニアか……あの国との腐れ縁はなかなか断ち切れないな。","ENG":"Gronia... It seems I have an ill-fated relationship with that country.","TWN":"葛羅尼亞...... 和那個國家每次都牽扯到不好的事情阿。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"기다리게. 그 유니콘한테서 연락이 온 모양이야.","JPN":"おっと、噂をすれば……あのユニコーンから連絡が来たようだな。","ENG":"Wait. I've got a phone call from that unicorn.","TWN":"等一下吧，好像那個獨角獸聯繫我們的樣子。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CALL_NPC_NULL_NULL","text":{"KOREA":"갑자기 이렇게 연락드려 죄송합니다. 잠시 통화 괜찮으시겠습니까?","JPN":"急なご連絡失礼いたします。少しお時間よろしいでしょうか？","ENG":"We're sorry to contact you on such short notice. May we have a moment of your time, sir?","TWN":"很抱歉這麼突然聯繫，方便和您電話嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"편할 대로 하시게. 소포도 일방적으로 보낸 마당에.","JPN":"今更こっちの都合を聞くのか？　宅急便もいきなり送ってきた君たちが？","ENG":"Go ahead. You already sent me a package without asking me first.","TWN":"你方便就好，包裹也不是隨便寄的嗎。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CALL_NPC_NULL_NULL","text":{"KOREA":"그 건에 대해선 드릴 말씀이 없습니다.","JPN":"その件については誠に申し訳ございません。","ENG":"We're sorry for the inconvenience, sir.","TWN":"針對那件事情我無話可說。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CALL_NPC_NULL_NULL","text":{"KOREA":"조사 결과, 직원의 실수로 오배송되었다고 합니다. <color=#ffd34c>상품</color>은 저희 측에서 즉시 회수하도록 하겠습니다.","JPN":"こちらでお調べしましたが、誤配送だったようです。<color=#ffd34c>商品</color>はすぐ回収いたします。","ENG":"We found out that one of our employees sent it to you by mistake. We'll send someone to collect the <color=#ffd34c>product</color> at once.","TWN":"經過調查，是我們員工寄錯了。<color=#ffd34c>商品</color>由我們會立即回收的。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아니. 번거롭게 그럴 필요 없네.","JPN":"いや、その必要はない。","ENG":"No, don't bother.","TWN":"哎呀，沒必要這麼麻煩。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네들이 보내 준 <color=#ffd34c>상품</color>, 마음에 들었어. 가능하면 생산된 동종 모델은 전부 받고 싶군.","JPN":"君たちの<color=#ffd34c>商品</color>、なかなか気に入ったよ。できれば同じ型番のモデルは全部受け取りたいんだが。","ENG":"I like the <color=#ffd34c>product</color> you sent me. If it's possible, I want all the units of the same model.","TWN":"你們寄來的<color=#ffd34c>商品</color>，我很喜歡。如果可以的話，已經生產的同種型號想全部拿到。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CALL_NPC_NULL_NULL","text":{"KOREA":"정말이십니까?","JPN":"本当ですか？","ENG":"Are you sure, sir?","TWN":"真的嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CALL_NPC_NULL_NULL","text":{"KOREA":"저희로서는 환영할 만한 이야기로군요. 그럼 곧장 결재를......","JPN":"こちらとしては、嬉しいご提案ですね。それではお支払いの準備を……","ENG":"Absolutely, we're happy to assist you. Now, for the payment—","TWN":"對我們來講是非常歡迎的事情，那麼就直接請款......"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이런, 나는 산다고 한 적은 없네. 사람 말은 끝까지 들어야지.","JPN":"話を最後まで聞け。買うとは一言も言ってないだろう？","ENG":"I didn't say I wanted to buy them. You didn't let me finish.","TWN":"哎呦，我沒說過要買，我的話還沒講完呢。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CALL_NPC_NULL_NULL","text":{"KOREA":"무슨 말씀이십니까?","JPN":"……それはどういう？","ENG":"Pardon?","TWN":"您是什麼意思呢？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"상품 소개에 하자가 있다는 점을 자네 고객들이 알면 어떻게 되겠나?","JPN":"商品の説明に偽りがあることを君たちの顧客が知ったらどうなるかな？","ENG":"Do your clients know that this product is defective?","TWN":"如果顧客知道商品有瑕疵會怎麼辦？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CALL_NPC_NULL_NULL","text":{"KOREA":"저희 회사 상품에 하자는 없습니다. 있다면 고객님의 과실로 생긴 문제겠죠.","JPN":"弊社の商品には偽りなどありません。お客様の扱い方が問題だったのかと。","ENG":"The product is not defective. If it is, that's because of a user error.","TWN":"我們公司商品並沒有瑕疵，如果有的話，就是顧客的過失而產生的問題。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래? 카운터는 그렇다 치더라도 워치도 복제했다는 건가?","JPN":"それはどうかな？カウンターはまあいいとして、ウォッチも複製できているのか？","ENG":"Okay, then did you clone the Counter and her Watch as well?","TWN":"是嗎？制裁者就不說了，能量環也複製了嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CALL_NPC_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"......"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그럴 리가. 원본이 자기 워치로 동생들에게 힘을 나눠 주고 있겠지.","JPN":"そんなはずないよな。オリジナルがウォッチを使って妹たちに力を分け与えているのだろう？","ENG":"Of course you didn't. The original is sharing her power with her sisters through her Watch.","TWN":"怎麼可能，是用自己本身的能量環分享給妹妹們力量了吧。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아무것도 모르고 다른 카운터들처럼 지내다간 순식간에 그림자로 전락할 걸세.","JPN":"これを知らずに普通のカウンターのように過ごしていたら、一瞬でただのシャドウになってしまうだろう。","ENG":"They're not like other Counters. They're bound to turn into Shadows at any moment.","TWN":"就像制裁者那樣什麼都不知道的樣子度過的話，一瞬間會淪爲陰影的。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그런 치명적인 문제를 모른 척 하다니, 너무 뻔뻔스럽지 않나?","JPN":"そんな致命的な問題を黙っているなんて、あまりにも図々しいと思うが。","ENG":"How can you be so shameless, trying to cover up such a critical flaw?","TWN":"那麼致命的問題還裝不知，是不是太厚顏無恥了？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CALL_NPC_NULL_NULL","text":{"KOREA":"......성가신 분이 걸렸군요.","JPN":"……なかなか厄介な方に商品が送られたようですね。","ENG":"... We've got a difficult customer at hand.","TWN":"......看來撞到麻煩的人了。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"CRF 측정도 제대로 되지 않는 모조품을 진짜 카운터 워치인 줄 착각하는 자네 고객들 수준이 떨어지는 거겠지.","JPN":"CRFの測定もできないレプリカと、本物のカウンターウォッチの区別もできない君たちの顧客の質が低いだけではないか？","ENG":"No. I'm just more educated than your clients who can't tell the difference between a real Watch and a knock-off that can't even measure CRF properly.","TWN":"把連CRF測定都做不好的仿冒品誤認爲是真正的制裁者能量環的你的顧客水平會下降吧。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CALL_NPC_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"......"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CALL_NPC_NULL_NULL","text":{"KOREA":"좋습니다. 어디까지나 프로모션용이니까요.","JPN":"いいでしょう。あくまでもプロモーション用の商品でしたからね。","ENG":"Okay, we get it. That product is still in the promotional stage.","TWN":"好吧，這只是宣傳用而已。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CALL_NPC_NULL_NULL","text":{"KOREA":"이번 건만 함구해 주신다면 남은 복제품들은 양도해 드리겠습니다.","JPN":"今回の件、誰にも言わないと約束してくださるなら、残りの複製品もすべてお譲りします。","ENG":"If you don't tell anyone about it, we'll give you all the remaining clones.","TWN":"只要這次能緘口不言，剩下的複製品就讓給您的。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러지. 자네들에게 너무 유리한 조건 같지만 말일세.","JPN":"約束しよう。君たちにとってはメリットしかない条件だと思わないか？","ENG":"I can agree to that even though it's still more favorable a condition to you than it's to me.","TWN":"好吧，這好像對你們的條件太有利了。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CALL_NPC_NULL_NULL","text":{"KOREA":"저희로서는 괜히 일을 키우지 않고 작은 손실에서 끝나면 만족할 뿐입니다. 지나친 주목을 받기엔 아직 이르거든요.","JPN":"この件が大事にならずに済むなら大した損失ではございません。我々としても、必要以上の注目は避けたいですからね。","ENG":"We're willing to accept a small loss because we don't want any more trouble. We're not ready for too much attention, just yet.","TWN":"對我們來說，只要不勞而獲，小損失結束就滿足了。 過分的關注還爲時尚早。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CALL_NPC_NULL_NULL","text":{"KOREA":"하지만 고객님의 경우 지금 같은 태도를 유지하시는 게, 사업상 썩 이로울 것 같진 않군요.","JPN":"ですがお客様、これからもこのような態度を取り続けるのであれば、いつか大変な目に遭いますよ。","ENG":"At the same time, you should consider changing your attitude if you want to stay in business.","TWN":"但是顧客現在保持這種態度，對生意不會太好。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"걱정해 줘서 고맙군.","JPN":"ご心配どうも。","ENG":"Thank you for your concern.","TWN":"謝謝你的擔心。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그런데 이미 내 목을 노리는 <color=#ffd34c>마왕</color> 같은 놈들이 한둘이 아니라서 말이야.","JPN":"言われなくても、私の首を狙う<color=#ffd34c>魔王</color>のようなやつらがうじゃうじゃいてね。","ENG":"But I already have enough people worrying about my safety from enemies like <color=#ffd34c>Demon Lords</color>.","TWN":"但是已經要我命的像 <color=#ffd34c>魔王</color> 般的傢伙們已經不止一兩個人了。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"굳이 그쪽에서 더 걱정해 줄 필요는 없네.","JPN":"十分気をつけているから、君の心配は要らないのさ。","ENG":"You don't have to add to them.","TWN":"沒必要你們再擔心。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CALL_NPC_NULL_NULL","text":{"KOREA":"마왕? 무슨 신종 농담인가요......?","JPN":"魔王……？　それは何かの冗談ですか？","ENG":"Demon Lords? Is that a new kind of joke?","TWN":"魔王？這是新型玩笑嗎......？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"흠. 아이들이 돌아 온 모양이군.","JPN":"おっと、子どもたちが帰ってきたようだな。","ENG":"Hmm. The children are back.","TWN":"嗯，好像孩子們回來的樣子。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"거래는 성사된 걸로 알겠네. 이만 끊지.","JPN":"とりあえず、取引は成立したと認識しておくよ。失礼。","ENG":"I take that our business is concluded. I'll hang up now.","TWN":"交易就當作成交了，我先掛了。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CALL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHILDREN_BARCODE_NULL_NULL","text":{"KOREA":"다녀왔습니다~!","JPN":"ただ～いま～！","ENG":"We're back!","TWN":"我回來啦~！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"오, 기운이 넘치는 걸 보니 두 사람 다 멋지게 심부름을 마치고 왔구나.","JPN":"その顔を見ると、無事お使いを終えたみたいだな。","ENG":"Oh, you look excited. Let me guess: you finished the errand with flying colors, didn't you?","TWN":"哦，看你們精力充沛的樣子，兩個人都瀟灑地跑腿回來了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래, 초콜릿은 맛있었니?","JPN":"チョコレートの味はどうだったんだい？","ENG":"Did you enjoy your chocolate?","TWN":"怎麼樣，巧克力好吃嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"응. 연구소에서 먹던 것보다 무지 달콤했어~","JPN":"あのね、研究所で食べていたものよりずっとずーっとおいしかったの！","ENG":"Yes. It was much sweeter than the one I ate at the lab.","TWN":"嗯，比在研究所吃的好甜好吃~"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"그런데 이러면 무승부잖아, 오빠. 소원은 어떻게 해?","JPN":"でも、勝負は引き分けになっちゃった。お兄ちゃん、わたしたちのお願いはどうなるの？","ENG":"But this means we tied, Brother. What happens to our wishes?","TWN":"但是這樣會平手吧，哥哥。願望怎麼辦？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"흐음...... 두 사람 다 잘했으니 전부 들어 주는 수밖에 없겠는데?","JPN":"ふむ……二人ともがんばったからな。二人のお願い、全部叶えてあげようかな？","ENG":"Hmm... Since both of you did so well, I'll have to grant all your wishes.","TWN":"嗯...... 兩個人都做得很好，只好兩個人都成全了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"CHILDREN_BARCODE_NULL_NULL","text":{"KOREA":"만세에~!","JPN":"本当に！？　やった～！","ENG":"Hurrah!","TWN":"萬歲~！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그럼 누구부터 먼저 말해 볼까?","JPN":"じゃあ、どっちから願い事を言うんだい？","ENG":"Okay, who wants to make a wish first?","TWN":"那麼誰先開始說呢？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"츠바이, 네가 먼저 말해도 돼.","JPN":"ツヴァイ、先に言っていいわ。","ENG":"Zwei, you can go ahead first.","TWN":"茨粨，你可以先說。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"아냐, 괜찮아. 아인이 언니잖아. 언니 먼저 해.","JPN":"ううん、大丈夫。アインがお姉ちゃんだから先にどうぞ。","ENG":"No. I can wait. Eins, you're older. You should go first.","TWN":"不用，沒關係。艾茵是姐姐啊，姐姐先吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 금방 사이가 좋아졌구나.","JPN":"何だ？　急に仲が良くなってるじゃないか。","ENG":"Hah hah. You've made up with each other.","TWN":"哈哈，兩個人關係很快就變好了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러면 아인부터 먼저 말해 보렴.","JPN":"じゃあ、アインから言ってみるかい？","ENG":"Okay, Eins. You first.","TWN":"那麼艾茵先開始吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"저기...... 그럼 있잖아......","JPN":"えっと、そ……それじゃあね……","ENG":"Then... mm...","TWN":"那個...... 那個嘛......"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"오빠가 앞으로도 쭉, 우리 오빠였으면 좋겠어.","JPN":"お兄ちゃんに、これからもずっとわたしたちのお兄ちゃんでいてほしいの。","ENG":"I want you to be our brother from now on. Forever.","TWN":"希望哥哥一直是我們的哥哥。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"나한테도, 츠바이한테도. 그리고 다른 동생들한테도.","JPN":"わたしにも、ツヴァイにも。それから、他の妹たちにも……","ENG":"To me, to Zwei, and to our other sisters.","TWN":"對我也是，對茨粨也是，還有其他妹妹們也是。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"역시 어른스럽구나. 그래, 그 소원은 꼭 들어 주마.","JPN":"さすがアインは大人だな。いいとも。その願い、必ず叶えてあげよう。","ENG":"You're so mature. Okay, your wish is granted.","TWN":"果然像大人的，好吧，我會成全你吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"헤헷......♪","JPN":"へへっ……♪","ENG":"Hee! ♪","TWN":"嘿嘿......♪"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"그러면 츠바이는~ 오빠랑 다 같이 놀이공원에 가고 싶어~","JPN":"あのね、ツヴァイはね～お兄ちゃんとみんなで遊園地に行きたいの！","ENG":"Then, Zwei wants to go to the theme park with you and everyone else.","TWN":"那麼茨粨是~ 想和哥哥一起去遊樂園~"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"여기, 아인이랑 같이 받은 자유이용권!","JPN":"ほら、ここに遊園地の1日パスポートがあるよ！","ENG":"Here, Eins and I earned these free passes!","TWN":"這裡，和艾茵一起拿到的自由使用卷！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_PRIDE"}}}},{"id":"L43_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"오, 이런 귀한 걸 어디서 구했니? 굉장한데?","JPN":"ほう、こんな貴重なものをどこで手に入れたんだい？","ENG":"Ooo, where did you get these expensive tickets? Good job!","TWN":"哦，這麼貴重的東西是從哪裡弄來的？ 很厲害啊？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"카페에 있던 지하실을 통과해서 받은 거야. 무서웠지만 츠바이랑 같이 있으니까 괜찮았어.","JPN":"カフェの地下室を一周してね、景品でもらったの。怖かったけど、ツヴァイと一緒だから大丈夫だったよ。","ENG":"We had to explore the cafe basement to win them. I wasn't scared because Zwei was with me.","TWN":"是在咖啡廳的地下室通關後獲得的，雖然很害怕，不過和茨粨在一起就覺得不怕了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"나도~ 아인이 아니었으면 엉엉 울었을 거야~","JPN":"ぼくも！　アインがいてくれなかったら、ひとりで泣いてたと思う！","ENG":"I wasn't, either. I would have cried like a baby if Eins wasn't there with me.","TWN":"我也是~ 如果不是艾茵我肯定會哭鬧的~"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"굉장한걸. 어른들은 한 번 사이가 나빠지면 다시 친해지지 못하는데, 너희는 금방 화해했구나.","JPN":"すごいなぁ。大人は一度喧嘩したらなかなか仲直りできないのに、君たちはあっという間に仲直りしているんだな。","ENG":"This is amazing. You two made up with each other so quickly. Even grownups have a hard time doing that.","TWN":"好厲害啊，大人們一旦關係不好就再也不能變好了，不過你們很快就和好了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 놀이공원은 조금 나중에 가야겠다. 너희 동생들도 곧 이리로 올 거거든.","JPN":"だけど遊園地は少しだけお預けにしようか。もうすぐ君たちの妹たちがここに来ることになってるからね。","ENG":"But the theme park will have to wait. Because your sisters are going to be here soon.","TWN":"不過遊樂園就下次再去吧，因為你們的妹妹即將來這裡。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"동생들이?!","JPN":"妹たちが！？","ENG":"Our sisters?","TWN":"妹妹們？！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"정말?!","JPN":"本当！？","ENG":"Really?","TWN":"真的？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그럼. 물론이지.","JPN":"ああ、もちろんさ。","ENG":"Yes, definitely.","TWN":"那當然。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그런데 동생들이 몇 명이나 되니? 세 명? 네 명?","JPN":"ところで、妹は全部で何人いるんだ？　3人？　それとも、4人か？","ENG":"By the way, how many sisters do you have? Three? Four?","TWN":"不過你們的妹妹是幾個？三個？四個？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CHILDREN_BARCODE_NULL_NULL","text":{"KOREA":"여덟 명!","JPN":"8人！","ENG":"Eight!","TWN":"是八個人！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......참 절제란 걸 모르는 놈들이군.","JPN":"……あいつら、限度ってもんがあるだろ……","ENG":"... Those jerks must not know when to stop.","TWN":"......真是不懂節制的傢伙們啊。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_BARCODE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"응? 오빠, 방금 뭐랬어?","JPN":"えっ、なになに？　なんて言ったの？","ENG":"Hm? Brother, did you say something?","TWN":"嗯？哥哥，你剛說什麼？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아니, 아무것도 아니란다.","JPN":"いや、なんでもないよ。","ENG":"Oh, nothing.","TWN":"沒有啊，沒什麼。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자, 그러면 다른 언니 오빠들이 오기 전에 사무실부터 정리해 두기로 할까?","JPN":"さて、他のお姉ちゃんとお兄ちゃんたちが戻ってくる前に事務所の片付けをしようかな？","ENG":"Now, would you two help me tidy up the office before the other employees return?","TWN":"那麼，在其他的姐姐哥哥們來前我們先整理辦公室吧？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"앗, 내가 먼저 정리할래~","JPN":"あっ、お片付けする～！","ENG":"Ooo, I'll go first!","TWN":"呃，我要先整理~"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CHILDREN_BARCODE_ONE_NULL","text":{"KOREA":"너 또 그 가면 쓰고 다니려고 그러지. 이제 내가 써 볼 차례야.","JPN":"ツヴァイ、またあのマスクつけて遊ぼうと思ってるんでしょ。今度はわたしがつけてみるんだから。","ENG":"You're going to wear that mask again, aren't you? It's my turn now!","TWN":"你又要戴那個面具是吧？這次輪到我了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"CHILDREN_BARCODE_TWO_NULL","text":{"KOREA":"안 돼~ 내가 찾은 거야~","JPN":"やだ～ぼくが見つけたんだもん～。","ENG":"No! I found it!","TWN":"不行~ 是我找來的~"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_BARCODE_ONE_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CHILDREN_BARCODE_TWO_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"미안하네. 너무 오래 기다리게 했군.","JPN":"すまん、だいぶ待たせたな。","ENG":"I'm sorry to have kept you waiting.","TWN":"對不起，讓你等太久了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"괜찮습니다. 실컷 일을 키워 놓고 떠넘기시는 게 한두 번도 아닌데요.","JPN":"問題ありません。厄介な仕事を増やして丸投げされることにはなれていますから。","ENG":"No worries. This isn't the first time you're dumping things on me.","TWN":"沒關係。把事情鬧大之後再推卸責任又不是一兩次了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하. 돌아오는 대로 올리비에 교수에게 메디컬 체크 좀 요청해 주게.","JPN":"ははっ。戻り次第、オリヴィエ教授にあの子たちのメディカルチェックを要請してくれないか？","ENG":"Hah hah. When you come back, please have Dr. Olivie give them a medical checkup.","TWN":"哈哈，回來後請奧利維亞教授檢查一下身體吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"조금 이상한 사람이어도 애들이라면 당분간 잘 보살펴 주겠지.","JPN":"ちょっと変わった人だけど……子ども相手なら優しく見てくれるかもしれないしな。","ENG":"She's a bit weird, but I can trust her with children.","TWN":"雖然是有點奇怪的人，不過只要是孩子，會好好照顧一段時間的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"정말 그렇게 생각하시나요?","JPN":"本当にそう思っているんですか？","ENG":"Can you? Really?","TWN":"真的會這麼想嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"미안하군. 사실 조교 얘기였어.","JPN":"……冗談だ。助手に頼むとしよう。","ENG":"Actually, I was talking about her assistant.","TWN":"對不起，其實是助教的事情了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 말이네만...... 그로니아의 최근 정세에 대해 좀 조사해 봐야겠더군.","JPN":"それから……グロニアの近頃の情勢について調査してみようと思う。","ENG":"And... maybe we should look into Gronia's recent political situation.","TWN":"還有就是……要調查一下葛羅尼亞最近的情況。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"의외로군요. 불필요한 마찰은 되도록 피하시는 게 방침 아니었나요?","JPN":"意外ですね。不要な揉め事は避けたかったんじゃないですか？","ENG":"This is rather unexpected. I thought you wanted to avoid unnecessary conflicts.","TWN":"真意外，您的方針不是儘量避免不必要的摩擦嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 잿더미만 남은 곳에서 인간복제 같은 최신 기술을 개발했을 것 같진 않아.","JPN":"あの灰だらけの地域で、人間の複製のような最新技術を開発したとは思えないからな。","ENG":"That place is nothing but a mound of ashes. There's no way it can give birth to such advanced technologies like human cloning.","TWN":"在只剩下灰燼的地方，似乎沒有開發出複製人類那種最新技術了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"문제가 될 여지가 있다면...... 미리 차단해야겠지.","JPN":"問題を起こす可能性がある危険な芽は、早めに摘んでおかないとな。","ENG":"If there's a problem, we'd better nip it in the bud.","TWN":"如果可能會成為問題的話......應該要提前切斷才對。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};